#!/usr/bin/env python3
"""
Bug #2615: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['constant', 'mul_zero_elim'], ['fusion', 'relu_add_relu'], ['broadcast', 'elu_scale'], ['branch', 'where_mask_fill'], ['normalization', 'variance_whitening'], ['branch', 'glu']]
Dependencies: numpy jax
Run         : python unique_2615.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])
_w3 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w4 = np.frombuffer(bytes.fromhex("000080bf"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("acc52737"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("0000003f"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1, 1, 1])
_w8 = np.frombuffer(bytes.fromhex("40000000000000004000000000000000"), dtype=np.int64).reshape([2])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 16, 128])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_mze_mz = x * _w0
    n0_mze_out = n0_mze_mz + _w1
    n100_rar_r1 = jnp.maximum(n0_mze_out, np.float32(0.0))
    n100_rar_ad = n100_rar_r1 + n0_mze_out
    n100_rar_out = jnp.maximum(n100_rar_ad, np.float32(0.0))
    n200_elus_elu = jnp.where(n100_rar_out >= np.float32(0.0), n100_rar_out, np.float32(1.0) * (jnp.exp(n100_rar_out) - np.float32(1.0)))
    n200_elus_out = n200_elus_elu + _w2
    n300_wmf_gt = (n200_elus_out > _w3)
    n300_wmf_wh = jnp.where(n300_wmf_gt, n200_elus_out, _w4)
    n300_wmf_out = n300_wmf_wh * n200_elus_out
    n400_vw_mean = jnp.mean(n300_wmf_out, axis=(-1,), keepdims=True)
    n400_vw_diff = n300_wmf_out - n400_vw_mean
    n400_vw_sq = n400_vw_diff * n400_vw_diff
    n400_vw_var = jnp.mean(n400_vw_sq, axis=(-1,), keepdims=True)
    n400_vw_add = n400_vw_var + _w5
    n400_vw_std = n400_vw_add ** np.float32(_w6.flat[0])
    n400_vw_div = n400_vw_diff / n400_vw_std
    n400_vw_out = n400_vw_div * _w7
    _split_18 = jnp.split(n400_vw_out, [64], axis=-1)
    n500_glu_a = _split_18[0]
    n500_glu_b = _split_18[1]
    n500_glu_sig = (np.float32(1.0) / (np.float32(1.0) + jnp.exp(-n500_glu_b)))
    n500_glu_out = n500_glu_a * n500_glu_sig
    return jnp.asarray(n500_glu_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
